import { useEffect, useRef } from 'react';
import type { Renderer } from '../renderer/Renderer';

interface Props {
  progress: number;
  renderer: Renderer;
}

export default function LoadingBar(props: Props) {
  const ref = useRef<HTMLDivElement>(null);
  const fillRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    props.renderer.loadingBars.push({
      ref: () => ref.current!,
      fillRef: () => fillRef.current!,
      fillPercent: () => Math.min(props.progress, 98),
    });
  }, []);

  return (
    <div ref={ref} className="loading-bar-composite">
      <div className="lb-bg" />
      <div
        ref={fillRef}
        className="lb-fill"
        style={{ width: Math.min(props.progress, 98) + '%' }}
      />
      <img className="lb-border" src="" alt="" />
      <img className="lb-glass" src="" alt="" />
      <div className="lb-text">{Math.floor(props.progress)}%</div>
    </div>
  );
}

