  const glowAlpha = progress < 5 ? 0 : progress > 95 ? 0 : Math.min((progress - 5) / 30, 1);

  return (
    <div className={`loading-screen${fading ? " loading-screen--fading" : ""}`}>
      <div className="loading-screen-content">
        <img src="/logo.avif" alt="WC3UI" className="loading-screen-logo" />

        <div className="loading-screen-bar-wrap">
          <div className="loading-bar-composite">
            <div
              className="lb-track"
              style={{
                left:   `${TRACK_LEFT}%`,
                right:  `${TRACK_RIGHT}%`,
                top:    `${TRACK_TOP}%`,
                bottom: `${TRACK_BOTTOM}%`,
              }}
            >
              <div
                className="lb-bg"
                style={{ backgroundImage: bgUrl ? `url("${bgUrl}")` : undefined }}
              />
              <div
                className="lb-fill"
                style={{
                  backgroundImage: fillUrl ? `url("${fillUrl}")` : undefined,
                  width: `${fillPct}%`,
                }}
              />
            </div>

            <img className="lb-border" src={borderUrl} alt="" />
            <img className="lb-glass"  src={glassUrl}  alt="" />

            {glowUrl && (
              <img
                className="lb-glow"
                src={glowUrl}
                alt=""
                style={{
                  left:    `${GLOW_LEFT}%`,
                  top:     `${GLOW_TOP}%`,
                  bottom:  `${GLOW_BOTTOM}%`,
                  width:   `${glowWidth}%`,
                  opacity: glowAlpha,
                }}
              />
            )}

            <div className="lb-text">{Math.floor(progress)}%</div>
          </div>
        </div>

        <p className="loading-screen-label">Loading…</p>
      </div>
    </div>
  );
}

