async function loadBlpDataUrl(path: string): Promise<string> {
  const cached = iconDataUrlCache.get(path);
  if (cached) return cached;

  const promise = (async () => {
    const res = await fetch(path);
    if (!res.ok) throw new Error(`Failed to fetch icon ${path}`);
    const ab = await res.arrayBuffer();
    const blp = decodeBLP(ab);
    const img = getBLPImageData(blp, 0);
    const pixelData = new Uint8ClampedArray(img.data);
    if (shouldForceOpaqueOnZeroAlpha(path)) {
      let allAlphaZero = true;
      for (let i = 3; i < pixelData.length; i += 4) {
        if (pixelData[i] !== 0) {
          allAlphaZero = false;
          break;
        }
      }
      if (allAlphaZero) {
        for (let i = 3; i < pixelData.length; i += 4) {
          pixelData[i] = 255;
        }
      }
    }
    if (shouldApplyBlackColorKey(path)) {
      for (let i = 0; i < pixelData.length; i += 4) {
        const r = pixelData[i];
        const g = pixelData[i + 1];
        const b = pixelData[i + 2];
        const a = pixelData[i + 3];
        if (a > 224 && r <= 10 && g <= 10 && b <= 10) {
          pixelData[i + 3] = 0;
        }
      }
    }
    const canvas = document.createElement("canvas");
    canvas.width = img.width;
    canvas.height = img.height;
    const ctx = canvas.getContext("2d");
    if (!ctx) throw new Error(`Failed to decode icon ${path}`);
    ctx.putImageData(new ImageData(pixelData, img.width, img.height), 0, 0);
    return canvas.toDataURL("image/png");
  })();

  iconDataUrlCache.set(path, promise);
  return promise;
}

async function loadDataUrlImage(url: string): Promise<HTMLImageElement> {
  const cached = decodedImageCache.get(url);
  if (cached) return cached;
  const promise = new Promise<HTMLImageElement>((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error(`Failed to load image ${url}`));
    img.src = url;
  });
  decodedImageCache.set(url, promise);
  return promise;
}

async function cropFrameRowToDataUrl(
  src: string,
  atlasRows = 1,
  atlasRow = 0,
): Promise<CroppedFrameRowResult> {
  const key = `${src}|${atlasRows}|${atlasRow}`;
  const cached = croppedFrameRowCache.get(key);
  if (cached) return cached;

  const promise = (async () => {
    const img = await loadDataUrlImage(src);
    const rows = Math.max(1, Math.floor(atlasRows));
    const rowHeight = Math.max(1, Math.floor(img.height / rows));
    const rowIndex = Math.max(0, Math.min(rows - 1, Math.floor(atlasRow)));
    const srcY = rowIndex * rowHeight;

    const rowCanvas = document.createElement("canvas");
    rowCanvas.width = img.width;
    rowCanvas.height = rowHeight;
    const rowCtx = rowCanvas.getContext("2d");
    if (!rowCtx) {
      return { url: src, width: img.width, height: rowHeight };
    }

    rowCtx.clearRect(0, 0, rowCanvas.width, rowCanvas.height);
    rowCtx.drawImage(
      img,
      0,
      srcY,
      img.width,
      rowHeight,
      0,
      0,
      img.width,
      rowHeight,
    );
    // Keep the full row including transparent gutters.
    // Template offsets are authored against the uncropped backdrop texture space.
    return {
      url: rowCanvas.toDataURL("image/png"),
      width: rowCanvas.width,
      height: rowCanvas.height,
    };
  })();

  croppedFrameRowCache.set(key, promise);
  return promise;
}

async function cropImageRegionToDataUrl(
  src: string,
  x: number,
  y: number,
  width: number,
  height: number,
): Promise<string> {
  const key = `${src}|${x}|${y}|${width}|${height}`;
  const cached = croppedImageRegionCache.get(key);
  if (cached) return cached;

  const promise = (async () => {
    const img = await loadDataUrlImage(src);
    const sx = Math.max(0, Math.min(img.width - 1, Math.floor(x)));
    const sy = Math.max(0, Math.min(img.height - 1, Math.floor(y)));
    const sw = Math.max(1, Math.min(img.width - sx, Math.floor(width)));
    const sh = Math.max(1, Math.min(img.height - sy, Math.floor(height)));
    const cropCanvas = document.createElement("canvas");
    cropCanvas.width = sw;
    cropCanvas.height = sh;
    const cropCtx = cropCanvas.getContext("2d");
    if (!cropCtx) return src;
    cropCtx.clearRect(0, 0, sw, sh);
    cropCtx.drawImage(img, sx, sy, sw, sh, 0, 0, sw, sh);
    return cropCanvas.toDataURL("image/png");
  })();

  croppedImageRegionCache.set(key, promise);
  return promise;
}

async function loadRaceCursorFrameDataUrl(race: Race): Promise<string> {
  const cached = cursorFrameDataUrlCache.get(race);
  if (cached) return cached;

  const promise = (async () => {
    const atlasDataUrl = await loadBlpDataUrl(`/cursor/${race}Cursor.blp`);
    const atlas = await loadDataUrlImage(atlasDataUrl);
    const columns = 8;
    const rows = 4;
    const frameW = Math.max(1, Math.floor(atlas.width / columns));
    const frameH = Math.max(1, Math.floor(atlas.height / rows));
    const canvas = document.createElement("canvas");
    canvas.width = frameW;
    canvas.height = frameH;
    const ctx = canvas.getContext("2d");
    if (!ctx) return atlasDataUrl;
    ctx.imageSmoothingEnabled = false;
    ctx.clearRect(0, 0, frameW, frameH);
    ctx.drawImage(atlas, 0, 0, frameW, frameH, 0, 0, frameW, frameH);
    return canvas.toDataURL("image/png");
  })();

  cursorFrameDataUrlCache.set(race, promise);
  return promise;
}

function rotateCellClockwise(
  atlas: HTMLImageElement,
  cellIndex: number,
  cellW: number,
  cellH: number,
): HTMLCanvasElement {
  const canvas = document.createElement("canvas");
  canvas.width = cellH;
  canvas.height = cellW;
  const ctx = canvas.getContext("2d");
  if (!ctx) return canvas;
  ctx.translate(cellH, 0);
  ctx.rotate(Math.PI / 2);
  ctx.drawImage(atlas, cellIndex * cellW, 0, cellW, cellH, 0, 0, cellW, cellH);
  return canvas;
}

function drawGlueNineSliceToCanvas(
  canvas: HTMLCanvasElement,
  bgImg: HTMLImageElement,
  borderImg: HTMLImageElement,
  hoverImg: HTMLImageElement | null,
  hovered: boolean,
) {
  const cssW = Math.max(1, canvas.clientWidth || 1);
  const cssH = Math.max(1, canvas.clientHeight || 1);
  const dpr = window.devicePixelRatio || 1;
  const pxW = Math.max(1, Math.round(cssW * dpr));
  const pxH = Math.max(1, Math.round(cssH * dpr));
  if (canvas.width !== pxW || canvas.height !== pxH) {
    canvas.width = pxW;
    canvas.height = pxH;
  }

  const ctx = canvas.getContext("2d");
  if (!ctx) return;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.clearRect(0, 0, cssW, cssH);

  const atlasW = borderImg.width;
  const atlasH = borderImg.height;
  const cellW = atlasW / 8;
  const corner = Math.max(
    1,
    Math.floor(Math.min(cellW, cssH * 0.35, cssW / 2, cssH / 2)),
  );
  const inset = Math.max(1, Math.round(corner * 0.25));

  // Fill inner area with opaque black before pattern to handle textures with alpha
  // (NightElf/Undead bg textures use DXT3/5 with alpha; game renders on opaque framebuffer)
  ctx.fillStyle = "#000";
  ctx.fillRect(inset, inset, cssW - inset * 2, cssH - inset * 2);

  const pattern = ctx.createPattern(bgImg, "repeat");
  if (pattern) {
    ctx.fillStyle = pattern;
    ctx.fillRect(inset, inset, cssW - inset * 2, cssH - inset * 2);
  }

  const drawCell = (
    idx: number,
    x: number,
    y: number,
    w: number,
    h: number,
  ) => {
    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
  };

  drawCell(4, 0, 0, corner, corner);
  drawCell(5, cssW - corner, 0, corner, corner);
  drawCell(6, 0, cssH - corner, corner, corner);
  drawCell(7, cssW - corner, cssH - corner, corner, corner);

  const edgeH = cssH - corner * 2;
  if (edgeH > 0) {
    drawCell(0, 0, corner, corner, edgeH);
    drawCell(1, cssW - corner, corner, corner, edgeH);
  }

  const edgeW = cssW - corner * 2;
  if (edgeW > 0) {
    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
    const bottomRot = rotateCellClockwise(borderImg, 3, cellW, atlasH);
    ctx.drawImage(topRot, corner, 0, edgeW, corner);
    ctx.drawImage(bottomRot, corner, cssH - corner, edgeW, corner);
  }

  if (hovered && hoverImg) {
    const temp = document.createElement("canvas");
    temp.width = pxW;
    temp.height = pxH;
    const tCtx = temp.getContext("2d");
    if (tCtx) {
      tCtx.setTransform(dpr, 0, 0, dpr, 0, 0);
      tCtx.drawImage(canvas, 0, 0, cssW, cssH);
      tCtx.globalCompositeOperation = "source-in";
      tCtx.drawImage(hoverImg, 0, 0, cssW, cssH);
      ctx.save();
      ctx.globalCompositeOperation = "lighter";
      ctx.drawImage(temp, 0, 0, cssW, cssH);
      ctx.restore();
    }
  }
}

interface NineSliceTemplateOptions {
  cornerPx: number;
  insetPx: number;
  tileBackground?: boolean;
  tileHorizontalEdges?: boolean;
  opaqueBaseFill?: string | null;
  fillCornerMaxPx?: number;
}

function drawHorizontallyTiledEdge(
  ctx: CanvasRenderingContext2D,
  tile: HTMLCanvasElement,
  x: number,
  y: number,
  width: number,
  height: number,
) {
  if (width <= 0 || height <= 0) return;

  let drawn = 0;
  while (drawn < width) {
    const segmentW = Math.min(height, width - drawn);
    const srcW = (segmentW / height) * tile.width;
    ctx.drawImage(
      tile,
      0,
      0,
      srcW,
      tile.height,
      x + drawn,
      y,
      segmentW,
      height,
    );
    drawn += segmentW;
  }
}

function drawTemplateNineSliceToCanvas(
  canvas: HTMLCanvasElement,
  bgImg: HTMLImageElement,
  borderImg: HTMLImageElement,
  options: NineSliceTemplateOptions,
) {
  const cssW = Math.max(1, canvas.clientWidth || 1);
  const cssH = Math.max(1, canvas.clientHeight || 1);
  const dpr = window.devicePixelRatio || 1;
  const pxW = Math.max(1, Math.round(cssW * dpr));
  const pxH = Math.max(1, Math.round(cssH * dpr));
  if (canvas.width !== pxW || canvas.height !== pxH) {
    canvas.width = pxW;
    canvas.height = pxH;
  }

  const ctx = canvas.getContext("2d");
  if (!ctx) return;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.clearRect(0, 0, cssW, cssH);

  const atlasW = borderImg.width;
  const atlasH = borderImg.height;
  const cellW = atlasW / 8;
  const sourceCornerMax = Math.max(1, Math.floor(Math.min(cellW, atlasH)));
  const corner = Math.max(
    1,
    Math.floor(Math.min(options.cornerPx, sourceCornerMax, cssW / 2, cssH / 2)),
  );
  const inset = Math.max(
    0,
    Math.floor(Math.min(options.insetPx, cssW / 2, cssH / 2)),
  );
  const innerX = inset;
  const innerY = inset;
  const innerW = Math.max(0, cssW - inset * 2);
  const innerH = Math.max(0, cssH - inset * 2);
  // Large controls (textarea/listbox) reuse the same nine-slice templates; cap fill corner
  // radius to prevent over-rounded clipping that exposes page background.
  const fillCornerCapPx = options.fillCornerMaxPx ?? 8;
  const fillCorner = Math.max(
    0,
    Math.floor(Math.min(corner, fillCornerCapPx, innerW / 2, innerH / 2)),
  );

  if (innerW > 0 && innerH > 0) {
    ctx.save();
    ctx.beginPath();
    if (fillCorner > 0) {
      ctx.roundRect(innerX, innerY, innerW, innerH, fillCorner);
    } else {
      ctx.rect(innerX, innerY, innerW, innerH);
    }
    ctx.clip();

    if (options.opaqueBaseFill) {
      ctx.fillStyle = options.opaqueBaseFill;
      ctx.fillRect(innerX, innerY, innerW, innerH);
    }
    if (options.tileBackground === false) {
      ctx.drawImage(
        bgImg,
        0,
        0,
        bgImg.width,
        bgImg.height,
        innerX,
        innerY,
        innerW,
        innerH,
      );
    } else {
      const pattern = ctx.createPattern(bgImg, "repeat");
      if (pattern) {
        ctx.fillStyle = pattern;
        ctx.fillRect(innerX, innerY, innerW, innerH);
      }
    }
    ctx.restore();
  }

  const drawCell = (
    idx: number,
    x: number,
    y: number,
    w: number,
    h: number,
  ) => {
    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
  };

  drawCell(4, 0, 0, corner, corner);
  drawCell(5, cssW - corner, 0, corner, corner);
  drawCell(6, 0, cssH - corner, corner, corner);
  drawCell(7, cssW - corner, cssH - corner, corner, corner);

  const edgeH = cssH - corner * 2;
  if (edgeH > 0) {
    drawCell(0, 0, corner, corner, edgeH);
    drawCell(1, cssW - corner, corner, corner, edgeH);
  }

  const edgeW = cssW - corner * 2;
  if (edgeW > 0) {
    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
    const bottomRot = rotateCellClockwise(borderImg, 3, cellW, atlasH);
    if (options.tileHorizontalEdges) {
      drawHorizontallyTiledEdge(ctx, topRot, corner, 0, edgeW, corner);
      drawHorizontallyTiledEdge(
        ctx,
        bottomRot,
        corner,
        cssH - corner,
        edgeW,
        corner,
      );
    } else {
      ctx.drawImage(topRot, corner, 0, edgeW, corner);
      ctx.drawImage(bottomRot, corner, cssH - corner, edgeW, corner);
    }
  }
}

function composeBorderImageFromAtlas(atlas: HTMLImageElement): string {
  const cellW = atlas.width / 8;
  const cellH = atlas.height;
  const cell = Math.max(1, Math.floor(Math.min(cellW, cellH)));
  const canvas = document.createElement("canvas");
  canvas.width = cell * 3;
  canvas.height = cell * 3;
  const ctx = canvas.getContext("2d");
  if (!ctx) return "";
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.imageSmoothingEnabled = false;

  const drawCell = (idx: number, x: number, y: number) => {
    ctx.drawImage(atlas, idx * cellW, 0, cellW, cellH, x, y, cell, cell);
  };

  drawCell(4, 0, 0);
  drawCell(5, cell * 2, 0);
  drawCell(6, 0, cell * 2);
  drawCell(7, cell * 2, cell * 2);
  drawCell(0, 0, cell);
  drawCell(1, cell * 2, cell);

  const top = rotateCellClockwise(atlas, 2, cellW, cellH);
  const bottom = rotateCellClockwise(atlas, 3, cellW, cellH);
  ctx.drawImage(top, cell, 0, cell, cell);
  ctx.drawImage(bottom, cell, cell * 2, cell, cell);

  return canvas.toDataURL("image/png");
}

function modelBarFillRatio(
  valuePct: number,
  profile: StatusBarFillProfile,
): number {
  const pct = Math.max(0, Math.min(100, valuePct));
  const scaleX =
    profile.minScaleX + ((profile.maxScaleX - profile.minScaleX) * pct) / 100;
  return Math.max(0, Math.min(1, profile.fillToFrameWidth * scaleX));
}

const additiveSrcColorScratchCanvas = document.createElement("canvas");

function compositeSrcColorAdditive(
  dstCtx: CanvasRenderingContext2D,
  pxW: number,
  pxH: number,
  dpr: number,
  cssW: number,
  cssH: number,
  drawSource: (ctx: CanvasRenderingContext2D) => void,
) {
  if (
    additiveSrcColorScratchCanvas.width !== pxW ||
    additiveSrcColorScratchCanvas.height !== pxH
  ) {
    additiveSrcColorScratchCanvas.width = pxW;
    additiveSrcColorScratchCanvas.height = pxH;
  }

  const srcCtx = additiveSrcColorScratchCanvas.getContext("2d");
  if (!srcCtx) return;
  srcCtx.setTransform(dpr, 0, 0, dpr, 0, 0);
  srcCtx.clearRect(0, 0, cssW, cssH);
  srcCtx.imageSmoothingEnabled = true;
  drawSource(srcCtx);

  const srcImage = srcCtx.getImageData(0, 0, pxW, pxH);
  const dstImage = dstCtx.getImageData(0, 0, pxW, pxH);
  const src = srcImage.data;
  const dst = dstImage.data;

  // Warcraft III Additive layer mode maps to GL blendFunc(SRC_COLOR, ONE).
  for (let i = 0; i < dst.length; i += 4) {
    const srcR = src[i] / 255;
    const srcG = src[i + 1] / 255;
    const srcB = src[i + 2] / 255;
    const srcA = src[i + 3] / 255;
    dst[i] = Math.min(255, dst[i] + Math.round(srcR * srcR * 255));
    dst[i + 1] = Math.min(255, dst[i + 1] + Math.round(srcG * srcG * 255));
    dst[i + 2] = Math.min(255, dst[i + 2] + Math.round(srcB * srcB * 255));
    dst[i + 3] = Math.min(255, dst[i + 3] + Math.round(srcA * srcA * 255));
  }

  dstCtx.putImageData(dstImage, 0, 0);
}

function drawSimpleStatusBarToCanvas(
  canvas: HTMLCanvasElement,
  fillImg: HTMLImageElement,
  borderImg: HTMLImageElement,
  highlightImg: HTMLImageElement | null,
  valuePct: number,
  fillProfile: StatusBarFillProfile,
  fillTint?: string,
) {
  const rect = canvas.getBoundingClientRect();
  const cssW = Math.max(1, rect.width);
  const cssH = Math.max(1, rect.height);
  const dpr = window.devicePixelRatio || 1;
  const pxW = Math.max(1, Math.round(cssW * dpr));
  const pxH = Math.max(1, Math.round(cssH * dpr));
  if (canvas.width !== pxW || canvas.height !== pxH) {
    canvas.width = pxW;
    canvas.height = pxH;
  }

  const ctx = canvas.getContext("2d");
  if (!ctx) return;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.clearRect(0, 0, cssW, cssH);
  ctx.imageSmoothingEnabled = true;

  const fillW = cssW * modelBarFillRatio(valuePct, fillProfile);
  if (fillW > 0) {
    ctx.drawImage(
      fillImg,
      0,
      0,
      fillImg.width,
      fillImg.height,
      0,
      0,
      fillW,
      cssH,
    );
    if (fillTint) {
      ctx.save();
      ctx.globalCompositeOperation = "multiply";
      ctx.fillStyle = fillTint;
      ctx.fillRect(0, 0, fillW, cssH);
      ctx.restore();
    }
  }

  if (highlightImg) {
    compositeSrcColorAdditive(ctx, pxW, pxH, dpr, cssW, cssH, (srcCtx) => {
      srcCtx.drawImage(
        highlightImg,
        0,
        0,
        highlightImg.width,
        highlightImg.height,
        0,
        0,
        cssW,
        cssH,
      );
    });
  }

  ctx.drawImage(
    borderImg,
    0,
    0,
    borderImg.width,
    borderImg.height,
    0,
    0,
    cssW,
    cssH,
  );
}

function mixRgb(
  a: [number, number, number],
  b: [number, number, number],
  t: number,
): [number, number, number] {
  const clamped = Math.max(0, Math.min(1, t));
  return [
    Math.round(a[0] + (b[0] - a[0]) * clamped),
    Math.round(a[1] + (b[1] - a[1]) * clamped),
    Math.round(a[2] + (b[2] - a[2]) * clamped),
  ];
}

function rgbHex([r, g, b]: [number, number, number]): string {
  return `#${[r, g, b].map((c) => c.toString(16).padStart(2, "0")).join("")}`;
}

function healthBarTint(pct: number): string {
  const p = Math.max(0, Math.min(100, pct));
  const low: [number, number, number] = [220, 42, 22];
  const mid: [number, number, number] = [238, 201, 46];
  const high: [number, number, number] = [67, 213, 61];

  if (p <= 35) return rgbHex(mixRgb(low, mid, p / 35));
  return rgbHex(mixRgb(mid, high, (p - 35) / 65));
}

function easeOutCubic(t: number): number {
  const clamped = Math.max(0, Math.min(1, t));
  return 1 - (1 - clamped) ** 3;
}

function interpolateKeyframes(
  ms: number,
  keyframes: ReadonlyArray<readonly [number, number]>,
): number {
  if (keyframes.length === 0) return 0;
  if (ms <= keyframes[0][0]) return keyframes[0][1];
  for (let i = 1; i < keyframes.length; i++) {
    const [frameMs, frameVal] = keyframes[i];
    const [prevMs, prevVal] = keyframes[i - 1];
    if (ms <= frameMs) {
      const t = (ms - prevMs) / Math.max(0.0001, frameMs - prevMs);
      return prevVal + (frameVal - prevVal) * t;
    }
  }
  return keyframes[keyframes.length - 1][1];
}

function loadingStutterPct(ms: number): number {
  const stutterFrames = [
    [0, 82.0],
    [130, 82.8],
    [230, 82.35],
    [340, 83.95],
    [430, 83.3],
    [560, 85.2],
    [650, 84.45],
    [780, 87.25],
    [870, 86.55],
    [940, 88.9],
    [1000, 90.0],
  ] as const;
  return interpolateKeyframes(ms, stutterFrames);
}

function loadingProgressPct(ms: number): number {
  const cycleMs = progressAnimCycleMs;
  const wrappedMs = ((ms % cycleMs) + cycleMs) % cycleMs;
  const finalMs = cycleMs - loadingSmoothToStutterMs - loadingStutterDurationMs;

  if (wrappedMs < loadingSmoothToStutterMs) {
    const t = wrappedMs / loadingSmoothToStutterMs;
    return easeOutCubic(t) * loadingStutterStartPct;
  }

  if (wrappedMs < loadingSmoothToStutterMs + loadingStutterDurationMs) {
    return loadingStutterPct(wrappedMs - loadingSmoothToStutterMs);
  }

  const finalT =
    (wrappedMs - loadingSmoothToStutterMs - loadingStutterDurationMs) /
    Math.max(1, finalMs);
  return (
    loadingStutterEndPct + easeOutCubic(finalT) * (100 - loadingStutterEndPct)
  );
}

function loadingGlowAlphaPct(pct: number): number {
  const clampedPct = Math.max(0, Math.min(100, pct));
  // LoadBar.mdx (Birth sequence) glow alpha keys:
  // frame 3333:0, 13333:0, 26667:1, 26800:0.
  const glowAlphaFrames = [
    [0, 0],
    [42.6135, 0],
    [99.4332, 1],
    [100, 0],
  ] as const;
  return interpolateKeyframes(clampedPct, glowAlphaFrames);
}

interface MenuFrameVariantCardProps {
  variant: MenuFrameVariantDef;
  glueBgUrl: string;
  glueBgDownUrl: string;
  glueBorderUrl: string;
  glueBorderDownUrl: string;
  glueHoverUrl: string;
}

function MenuFrameVariantCard(props: MenuFrameVariantCardProps) {
  const buttonCanvasRef = useRef<HTMLCanvasElement>(null);

  const [hovered, setHovered] = useState(false);
  const [pressed, setPressed] = useState(false);
  const [frameSrc, setFrameSrc] = useState("");

  const buttonTextAfterHotkey = (() => {
    const text = props.variant.buttonText;
    const hotkey = props.variant.buttonHotkey;
    if (!hotkey) return text;
    if (text.toLowerCase().startsWith(hotkey.toLowerCase())) {
      return text.slice(hotkey.length);
    }
    return text;
  })();

  const buttonPlacementStyle = (() => {
    const p = props.variant.buttonPlacement;
    const leftPct =
      p.anchor === "top-left"
        ? (p.offsetX / p.backdropW) * 100
        : 100 - ((p.offsetX + p.buttonW) / p.backdropW) * 100;
    const rightPct = 100 - leftPct - (p.buttonW / p.backdropW) * 100;
    const topPct = (p.offsetY / p.backdropH) * 100;
    const bottomPct = 100 - topPct - (p.buttonH / p.backdropH) * 100;
    return {
      left: `${leftPct}%`,
      right: `${rightPct}%`,
      top: `${topPct}%`,
      bottom: `${bottomPct}%`,
    } as const;
  })();

  useEffect(() => {
    const src = props.variant.src;
    if (!src) {
      setFrameSrc("");
      return;
    }
    let cancelled = false;

    void cropFrameRowToDataUrl(
      src,
      props.variant.atlasRows ?? 1,
      props.variant.atlasRow ?? 0,
    )
      .then((result) => {
        if (cancelled) return;
        setFrameSrc(result.url);
      })
      .catch((err) => console.error(err));

    return () => {
      cancelled = true;
    };
  }, [props.variant.src, props.variant.atlasRows, props.variant.atlasRow]);

  useEffect(() => {
    const canvas = buttonCanvasRef.current;
    const bgUrl = pressed ? props.glueBgDownUrl : props.glueBgUrl;
    const borderUrl = pressed ? props.glueBorderDownUrl : props.glueBorderUrl;
    const hoverActive = hovered && !pressed;
    const hoverUrl = props.glueHoverUrl;
    if (!canvas || !bgUrl || !borderUrl) return;
    let cancelled = false;

    void Promise.all([
      loadDataUrlImage(bgUrl),
      loadDataUrlImage(borderUrl),
      hoverUrl ? loadDataUrlImage(hoverUrl) : Promise.resolve(null),
    ])
      .then(([bgImg, borderImg, hoverImg]) => {
        if (cancelled) return;
        drawGlueNineSliceToCanvas(
          canvas,
          bgImg,
          borderImg,
          hoverImg,
          hoverActive,
        );
      })
      .catch((err) => console.error(err));

    return () => {
      cancelled = true;
    };
  }, [
    pressed,
    hovered,
    props.glueBgUrl,
    props.glueBgDownUrl,
    props.glueBorderUrl,
    props.glueBorderDownUrl,
    props.glueHoverUrl,
  ]);

  return (
    <div className="button-preview-col">
      <div
        className="menu-frame-variant-shell"
        style={{
          width: `${props.variant.widthPx}px`,
          height: `${props.variant.heightPx}px`,
        }}
      >
        {frameSrc && (
          <img src={frameSrc} alt="" className="menu-frame-variant-image" />
        )}
        <button
          type="button"
          className={`menu-button-inner menu-frame-variant-inner${props.variant.innerTemplate === "tiny" ? " menu-frame-variant-inner--tiny" : ""}`}
          style={buttonPlacementStyle}
          onMouseEnter={() => setHovered(true)}
          onMouseLeave={() => {
            setHovered(false);
            setPressed(false);
          }}
          onMouseDown={() => setPressed(true)}
          onMouseUp={() => setPressed(false)}
        >
          <canvas ref={buttonCanvasRef} className="menu-button-canvas" />
          <span
            className="menu-button-label"
            style={{
              transform: pressed
                ? `translate(${glueButtonPressedOffsetXPx}px, ${glueButtonPressedOffsetYPx}px)`
                : "none",
            }}
          >
            {props.variant.buttonHotkey && (
              <span className="button-hotkey">
                {props.variant.buttonHotkey}
              </span>
            )}
            {buttonTextAfterHotkey}
          </span>
        </button>
      </div>
      <div className="button-state-label">{props.variant.label}</div>
    </div>
  );
}

