    10→const GLOW_LEFT    = 5.919;
    11→const GLOW_TOP     = -19.58;
    12→const GLOW_BOTTOM  = -19.49;
    13→const GLOW_SPAN    = 93.631;
    14→const MIN_FILL     = 1.23442;
    15→
    16→/** Duration of the progress animation in ms. */
    17→const DURATION_MS = 2400;
    18→/** Extra hold at 100% before fading out (ms). */
    19→const HOLD_MS = 300;
    20→/** Fade-out duration (ms). */
    21→const FADE_MS = 400;
    22→
    23→function easeInOut(t: number): number {
    24→  return t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t;
    25→}
    26→
    27→interface Props {
    28→  onDone: () => void;
    29→}
    30→
    31→export default function LoadingScreen({ onDone }: Props) {
    32→  const [bgUrl, setBgUrl]         = useState("");
    33→  const [fillUrl, setFillUrl]     = useState("");
    34→  const [borderUrl, setBorderUrl] = useState("");
    35→  const [glassUrl, setGlassUrl]   = useState("");
    36→  const [glowUrl, setGlowUrl]     = useState("");
    37→
    38→  const [progress, setProgress] = useState(0);
    39→  const [fading, setFading]     = useState(false);
    40→  const startRef = useRef<number | null>(null);
    41→  const rafRef   = useRef<number>(0);
    42→
    43→  // Load BLP assets
    44→  useEffect(() => {
    45→    void loadBlpDataUrl("/loading/Loading-BarBackground.blp").then(setBgUrl);
    46→    void loadBlpDataUrl("/loading/Loading-BarFill.blp").then(setFillUrl);
    47→    void loadBlpDataUrl("/loading/Loading-BarBorder.blp").then(setBorderUrl);
    48→    void loadBlpDataUrl("/loading/Loading-BarGlass.blp").then(setGlassUrl);
    49→    void loadBlpDataUrl("/loading/Loading-BarGlow.blp").then(setGlowUrl);
    50→  }, []);
    51→
    52→  // Progress animation
    53→  useEffect(() => {
    54→    let done = false;
    55→
    56→    function tick(ts: number) {
    57→      if (done) return;
    58→      if (startRef.current === null) startRef.current = ts;
    59→      const elapsed = ts - startRef.current;
    60→      const t = Math.min(elapsed / DURATION_MS, 1);
    61→      const pct = easeInOut(t) * 100;
    62→      setProgress(pct);
    63→
    64→      if (t < 1) {
    65→        rafRef.current = requestAnimationFrame(tick);
    66→      } else {
    67→        // Hold at 100%, then fade
    68→        setTimeout(() => {
    69→          if (done) return;
    70→          setFading(true);
    71→          setTimeout(() => {
    72→            if (!done) onDone();
    73→          }, FADE_MS);
    74→        }, HOLD_MS);
    75→      }
    76→    }
    77→
    78→    rafRef.current = requestAnimationFrame(tick);
    79→    return () => {
    80→      done = true;
    81→      cancelAnimationFrame(rafRef.current);
    82→    };
    83→  }, [onDone]);
    84→
    85→  const fillPct   = Math.max(MIN_FILL, progress);
    86→  const glowWidth = (fillPct / 100) * GLOW_SPAN;
    87→  // Simple glow alpha: ramps up in the middle of the animation
    88→  const glowAlpha = progress < 5 ? 0 : progress > 95 ? 0 : Math.min((progress - 5) / 30, 1);
    89→
    90→  return (
    91→    <div className={`loading-screen${fading ? " loading-screen--fading" : ""}`}>
    92→      <div className="loading-screen-content">
    93→        <img src="/logo.avif" alt="WC3UI" className="loading-screen-logo" />
    94→
    95→        <div className="loading-screen-bar-wrap">
