   101→                right:  `${TRACK_RIGHT}%`,
   102→                top:    `${TRACK_TOP}%`,
   103→                bottom: `${TRACK_BOTTOM}%`,
   104→              }}
   105→            >
   106→              <div
   107→                className="lb-bg"
   108→                style={{ backgroundImage: bgUrl ? `url("${bgUrl}")` : undefined }}
   109→              />
   110→              <div
   111→                className="lb-fill"
   112→                style={{
   113→                  backgroundImage: fillUrl ? `url("${fillUrl}")` : undefined,
   114→                  width: `${fillPct}%`,
   115→                }}
   116→              />
   117→            </div>
   118→
   119→            <img className="lb-border" src={borderUrl} alt="" />
   120→            <img className="lb-glass"  src={glassUrl}  alt="" />
   121→
   122→            {glowUrl && (
   123→              <img
   124→                className="lb-glow"
   125→                src={glowUrl}
   126→                alt=""
   127→                style={{
   128→                  left:    `${GLOW_LEFT}%`,
   129→                  top:     `${GLOW_TOP}%`,
   130→                  bottom:  `${GLOW_BOTTOM}%`,
   131→                  width:   `${glowWidth}%`,
   132→                  opacity: glowAlpha,
   133→                }}
   134→              />
   135→            )}
   136→
   137→            <div className="lb-text">{Math.floor(progress)}%</div>
   138→          </div>
   139→        </div>
   140→
   141→        <p className="loading-screen-label">Loading…</p>
   142→      </div>
   143→    </div>
   144→  );
   145→}
