/* ── Right column: step table ── */
.build-card-steps-wrapper {
  display: flex;
  flex-direction: row;
  min-height: 0;
}

.build-card-steps-wrapper .glue-scrollbar-demo {
  flex-shrink: 0;
  padding: 6px 4px;
  align-self: stretch;
}

.build-card-steps-wrapper .glue-scroll-track {
  flex: 1;
}

.build-card-steps {
  flex: 1;
  min-width: 0;
  padding: 0;
  overflow-x: auto;
  overflow-y: auto;
  max-height: 420px;
  scrollbar-width: none;
}

.build-card-steps::-webkit-scrollbar {
  display: none;
}

.build-steps-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  font-size: 0.8rem;
}

.build-steps-table thead tr {
  border-bottom: 1px solid rgba(252, 211, 18, 0.3);
}

.build-steps-table th {
  padding: 0.35rem 0.6rem;
  text-align: left;
  color: var(--wc3-gold);
  font-size: 0.68rem;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  font-weight: normal;
  border-bottom: 1px solid rgba(252, 211, 18, 0.3);
  position: sticky;
  top: 0;
  background: rgba(10, 8, 4, 0.95);
  z-index: 1;
}

.build-steps-table td {
  padding: 0.35rem 0.6rem;
  color: #dbe4ff;
  vertical-align: middle;
}

/* ── Step states ── */
.build-step-row {
  transition: opacity 0.15s ease;
  /* Reserve border space on every row so the active border doesn't shift layout */
  border: 6px solid transparent;
}

.build-step-row--past {
  opacity: 0.4;
}

.build-step-row--active {
  opacity: 1;
  background: rgba(252, 211, 18, 0.06);
}

.build-step-row--active td {
  color: var(--wc3-gold);
  text-shadow: 0 0 6px rgba(252, 211, 18, 0.35);
}

.build-step-order {
  width: 1.8rem;
  color: rgba(252, 211, 18, 0.5);
  font-size: 0.7rem;
  text-align: center;
}

.build-step-time {
  width: 3.5rem;
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}

.build-step-instruction {
  /* takes remaining space */
}

.build-steps-table th:last-child {
  text-align: right;
}

.build-step-food {
  width: 5rem;
  white-space: nowrap;
  text-align: right;
  font-variant-numeric: tabular-nums;
}

.build-step-food-icon {
  width: 12px;
  height: 12px;
  vertical-align: -1px;
  margin-right: 3px;
  image-rendering: pixelated;
}

/* ── Skill order section ── */
.skill-order-section {
  margin-top: 0.75rem;
  padding: 0.85rem 1.25rem;
}

.skill-order-title {
  margin: 0 0 0.85rem;
  font-size: 0.72rem;
  color: var(--wc3-gold);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-weight: normal;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  text-shadow: 0 0 6px rgba(252, 211, 18, 0.25);
}

.skill-order-title::before,
.skill-order-title::after {
  content: "";
  flex: 1;
  height: 1px;
  background: linear-gradient(
    90deg,
    transparent,
    rgba(252, 211, 18, 0.3) 20%,
    rgba(252, 211, 18, 0.3) 80%,
    transparent
  );
}

.skill-order-row {
  display: flex;
  align-items: flex-start;
  width: 100%;
}

.skill-pick {
  display: flex;
  align-items: center;
  flex: 1;
  min-width: 0;
}

.skill-pick:last-child {
  flex: 0 0 auto;
}

.skill-pick-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.35rem;
  flex-shrink: 0;
}

.skill-pick-icon-wrapper {
  position: relative;
  width: 42px;
  height: 42px;
  border: 1px solid rgba(252, 211, 18, 0.35);
  background: rgba(0, 0, 0, 0.55);
}

.skill-pick-level {
  position: absolute;
  top: -1px;
  left: -1px;
  font-size: 0.52rem;
  color: #fcd312;
  background: rgba(0, 0, 0, 0.8);
  border: 1px solid rgba(252, 211, 18, 0.3);
  border-top: none;
  border-left: none;
  padding: 1px 4px;
  z-index: 1;
  font-weight: bold;
  letter-spacing: 0.02em;
  line-height: 1;
}

.skill-pick-icon {
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  object-fit: cover;
}

.skill-pick-icon--placeholder {
  width: 100%;
  height: 100%;
  background: rgba(252, 211, 18, 0.06);
}

.skill-pick-name {
  font-size: 0.62rem;
  color: #c8b97a;
  text-align: center;
  line-height: 1.2;
  white-space: nowrap;
}

.skill-pick-connector {
  flex: 1;
  height: 1px;
  min-width: 8px;
  margin: 0 0.35rem;
  margin-top: 21px;
  background: linear-gradient(
    90deg,
    rgba(252, 211, 18, 0.4),
    rgba(252, 211, 18, 0.15)
  );
}

@media (max-width: 700px) {
  .build-card {
    grid-template-columns: 1fr;
  }

  .build-card-info {
    border-right: none;
    border-bottom: 1px solid rgba(252, 211, 18, 0.2);
  }
}

