.portrait-showcase {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}

.portrait-stage-wrap {
  position: relative;
  width: min(225px, 52vw);
}

.portrait-stage {
  position: relative;
  width: 100%;
  aspect-ratio: 130 / 160;
