  background: radial-gradient(
    circle at 50% 50%,
    rgba(0, 0, 0, 0) 32%,
    rgba(0, 0, 0, 0.68) 100%
  );
  pointer-events: none;
}

.minimap-ping {
  position: absolute;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  border: 1px solid rgba(255, 255, 255, 0.75);
  box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.45);
  animation: minimap-ping 1.8s ease-out infinite;
}

.minimap-ping--a {
  left: 26%;
  top: 34%;
  background: #58d869;
}

.minimap-ping--b {
  left: 61%;
  top: 54%;
  background: #e65a5a;
  animation-delay: 0.6s;
}

.minimap-ping--c {
  left: 47%;
  top: 20%;
  background: #f0d775;
  animation-delay: 1.1s;
}

@keyframes minimap-ping {
  0% {
    box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.45);
  }
  100% {
    box-shadow: 0 0 0 12px rgba(255, 255, 255, 0);
