```

---

## Example 2: Section with Local State

A section that manages its own UI state with `useState`.

**`src/components/sections/CounterSection.tsx`**
```tsx
interface Props {
  count: number;
  onIncrement: () => void;
  counterPressed: boolean;
  counterCanvasRef: React.RefObject<HTMLCanvasElement | null>;
  onCounterMouseEnter: () => void;
  onCounterMouseLeave: () => void;
  onCounterMouseDown: () => void;
  onCounterMouseUp: () => void;
}
export default function CounterSection(props: Props) {
  return (
    <section className="section-card counter-section">
      <h3>Counter</h3>
      <p className="counter-value">{props.count}</p>
      <div className="counter-buttons">
        <button
          type="button"
          className="esc-option-preview counter-btn"
          onMouseEnter={props.onCounterMouseEnter}
          onMouseLeave={props.onCounterMouseLeave}
          onMouseDown={() => {
            props.onCounterMouseDown();
            props.onIncrement();
          }}
          onMouseUp={props.onCounterMouseUp}
        >
          <canvas ref={props.counterCanvasRef} className="esc-option-canvas" />
          <span
            className="esc-option-label"
            style={{
              transform: props.counterPressed ? "translate(2px, 2px)" : "none",
            }}
          >
            +1
          </span>
        </button>
      </div>
    </section>
  );
}
```
and add this at:
**`src/App.tsx`**
```tsx

// other app code...

import CounterSection from "./components/sections/CounterSection";

// other app code...

const [counterHovered, setCounterHovered] = useState(false);
const [counterPressed, setCounterPressed] = useState(false);
const [counterCount, setCounterCount] = useState(0);

// other app code...

const handleIncrement = () => {
    setCounterCount(prev => prev + 1);
  };

// other app code...

 // Effect: count canvas
  useEffect(() => {
    const canvas = counterCanvasRef.current;
    const bgUrlVal = counterPressed ? escBgDownUrl : escBgUrl;
    const borderUrlVal = counterPressed
      ? escBorderDownUrl
      : escBorderUrl;
    const hoverActive = counterHovered && !counterPressed;
    const hoverUrlVal = escHoverUrl;
    if (!canvas || !bgUrlVal || !borderUrlVal) return;
    let cancelled = false;

    void Promise.all([
      loadDataUrlImage(bgUrlVal),
      loadDataUrlImage(borderUrlVal),
      hoverUrlVal ? loadDataUrlImage(hoverUrlVal) : Promise.resolve(null),
    ])
      .then(([bgImg, borderImg, hoverImg]) => {
        if (cancelled) return;
        drawGlueNineSliceToCanvas(
          canvas,
          bgImg,
          borderImg,
          hoverImg,
          hoverActive,
        );
      })
      .catch((err) => console.error(err));

    return () => {
      cancelled = true;
    };
  }, [
    counterPressed,
    counterHovered,
    escBgUrl,
    escBgDownUrl,
    escBorderUrl,
    escBorderDownUrl,
    escHoverUrl,
  ]);

// other app code...

  <div className="showcase-flow-item showcase-flow-item--counter">
    <CounterSection 
      count={counterCount}                     // ← new
      onIncrement={handleIncrement}
      counterPressed={counterPressed}
      counterCanvasRef={counterCanvasRef}
      onCounterMouseEnter={() => setCounterHovered(true)}
      onCounterMouseLeave={() => {
        setCounterHovered(false);
        setCounterPressed(false);
      }}
      onCounterMouseDown={() => {
        setCounterPressed(true);
      }}
      onCounterMouseUp={() => setCounterPressed(false)}
    />
  </div>
```

> The `esc-option-preview` and `esc-option-label` classes are the WC3-styled button from HeroSection. They give you the gold frame button look for free.

---

## Example 3: Global State Store

When state needs to be shared between sections or accessed outside React, use the external store pattern.

**`src/state/counter.ts`**
```ts
import { createExternalStore } from './createStore';

// --- Stores ---
const countStore = createExternalStore<number>(0);

// --- Non-reactive getters (use anywhere) ---
export const getCount = countStore.get;

// --- Setters (use anywhere) ---
export const setCount = countStore.set;

// --- Helper actions ---
export function increment() {
  countStore.set(prev => prev + 1);
}
export function decrement() {
  countStore.set(prev => prev - 1);
}
export function reset() {
  countStore.set(0);
}

// --- Hooks (use in React components only) ---
export const useCount = countStore.useValue;
```

**Using the store in a section:**
```tsx
import { useCount, increment, decrement, reset } from '../../state/counter';

export default function CounterSection() {
  const count = useCount(); // reactive — re-renders when count changes

  return (
    <section className="section-card counter-section">
      <h3>Count: {count}</h3>
      <button type="button" onClick={decrement}>−</button>
      <button type="button" onClick={increment}>+</button>
      <button type="button" onClick={reset}>Reset</button>
    </section>
  );
}
```

**Using the store outside React** (e.g., from a timer callback):
```ts
import { getCount, setCount } from './state/counter';

setInterval(() => {
  const current = getCount(); // read without subscribing
  setCount(current + 1);      // write — triggers re-renders in subscribed components
}, 1000);
```

---

## Example 4: Race-Aware Section

A section that reads the active race and changes its content accordingly.

**`src/components/sections/RaceInfoSection.tsx`**
```tsx
import { useCurrentRace } from '../../state/race';

const RACE_DESCRIPTIONS: Record<string, string> = {
  Human:    'The Alliance. Builds towers, trains Footmen, expands fast.',
  Orc:      'The Horde. Blade Master rushes and Grunt armies.',
  NightElf: 'The night elves. Moon Wells, Wisps, and Demon Hunters.',
  Undead:   'The Scourge. Death Knights, Ghouls, and Necromancers.',
};

export default function RaceInfoSection() {
  const race = useCurrentRace(); // re-renders whenever the user switches race

  return (
    <section className="section-card race-info-section">
      <h3>{race}</h3>
      <p>{RACE_DESCRIPTIONS[race]}</p>
    </section>
  );
}
```

> The race switches when the user clicks a faction tab in the top HUD. Your section automatically re-renders.

---

## Example 5: Timer with setInterval

A section with a running timer — the pattern for the build order timer.

**`src/state/timer.ts`**
```ts
import { createExternalStore } from './createStore';

const runningStore = createExternalStore<boolean>(false);
const elapsedStore = createExternalStore<number>(0); // seconds

let intervalId: ReturnType<typeof setInterval> | null = null;

export function startTimer() {
  if (runningStore.get()) return; // already running
  runningStore.set(true);
  intervalId = setInterval(() => {
    elapsedStore.set(prev => prev + 1);
  }, 1000);
}

export function pauseTimer() {
  if (intervalId !== null) {
    clearInterval(intervalId);
    intervalId = null;
  }
  runningStore.set(false);
}

export function resetTimer() {
  pauseTimer();
  elapsedStore.set(0);
}

export const useTimerRunning = runningStore.useValue;
export const useElapsedSeconds = elapsedStore.useValue;
export const getElapsedSeconds = elapsedStore.get;
```

**`src/components/sections/TimerSection.tsx`**
```tsx
import {
  useTimerRunning,
  useElapsedSeconds,
  startTimer,
  pauseTimer,
  resetTimer,
} from '../../state/timer';

function formatTime(seconds: number): string {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toString().padStart(2, '0')}`;
}

export default function TimerSection() {
  const running = useTimerRunning();
  const elapsed = useElapsedSeconds();

  return (
    <section className="section-card timer-section">
      <h3>Timer</h3>
      <div className="timer-display">{formatTime(elapsed)}</div>
      <div className="timer-controls">
        {running ? (
          <button type="button" className="esc-option-preview" onClick={pauseTimer}>
            <span className="esc-option-label">Pause</span>
          </button>
        ) : (
          <button type="button" className="esc-option-preview" onClick={startTimer}>
            <span className="esc-option-label">Start</span>
          </button>
        )}
        <button type="button" className="esc-option-preview" onClick={resetTimer}>
          <span className="esc-option-label">Reset</span>
        </button>
      </div>
    </section>
  );
}
```

**CSS in `src/global.css`:**
```css
.timer-section {
  text-align: center;
  padding: 2rem;
}

.timer-display {
  font-family: 'Friz Quadrata', serif;
  font-size: 4rem;
  color: #fcd312;
  margin: 1rem 0;
  letter-spacing: 0.05em;
}

.timer-controls {
  display: flex;
  gap: 1rem;
  justify-content: center;
  margin-top: 1rem;
}
```

---

## Example 6: Adding a New Page

Pages are full-screen views that replace the showcase flow. They are rendered inside the same viewport and top HUD, but the showcase sections are hidden while a page is active.

### How it works

- **`src/state/page.ts`** — a store holding the active page ID (`"showcase"` = default showcase flow)
- **`src/pages/index.ts`** — a registry mapping page IDs to their React components
- **`src/App.tsx`** — renders the page from the registry, or falls back to the showcase flow

### Step 1: Create the page component

**`src/pages/MyPage.tsx`**
```tsx
import GlueSmallButton from "../components/GlueSmallButton";
import { setPage } from "../state/page";

export default function MyPage() {
  return (
    <div className="tab-content tab-content--page">
      <div className="page-nav">
        <GlueSmallButton onClick={() => setPage("showcase")}>
          Back
        </GlueSmallButton>
      </div>
      <section className="section-card">
        <h3>My Custom Page</h3>
        <p>This is a full-screen page that replaces the showcase.</p>
      </section>
    </div>
  );
}
```

- Use `tab-content tab-content--page` for proper max-width and padding
- Use `page-nav` for a back-button row at the top
- Add any sections or custom content below

### Step 2: Register the page

**`src/pages/index.ts`**
```ts
import type { ComponentType } from "react";
import BuildOrderPage from "./BuildOrderPage";
import MyPage from "./MyPage";

export const PAGE_REGISTRY: Record<string, ComponentType> = {
  "build-orders": BuildOrderPage,
  "my-page": MyPage,  // ← add your page here
};
```

That's it — the page ID `"my-page"` now maps to your component. `App.tsx` looks up the registry automatically.

### Step 3: Navigate to the page

From anywhere in the app (components, callbacks, event handlers):

```tsx
import { setPage } from "../state/page";

// Navigate to your page
setPage("my-page");

// Go back to the showcase
setPage("showcase");
```

You can use any WC3-styled button to trigger navigation:

```tsx
import GlueSmallButton from "../components/GlueSmallButton";
import { setPage } from "../state/page";

<GlueSmallButton onClick={() => setPage("my-page")}>
  Open My Page
</GlueSmallButton>
```

### Step 4 (optional): Read the active page

To conditionally render UI based on the current page:

```tsx
import { usePage } from "../state/page";

function MyComponent() {
  const page = usePage(); // reactive — re-renders on page change
  return <span>Current page: {page}</span>;
}
```

