## Example 2: Section with Local State

A section that manages its own UI state with `useState`.

**`src/components/sections/CounterSection.tsx`**
```tsx
interface Props {
  count: number;
  onIncrement: () => void;
  counterPressed: boolean;
  counterCanvasRef: React.RefObject<HTMLCanvasElement | null>;
  onCounterMouseEnter: () => void;
  onCounterMouseLeave: () => void;
  onCounterMouseDown: () => void;
  onCounterMouseUp: () => void;
}
export default function CounterSection(props: Props) {
  return (
    <section className="section-card counter-section">
      <h3>Counter</h3>
      <p className="counter-value">{props.count}</p>
      <div className="counter-buttons">
        <button
          type="button"
          className="esc-option-preview counter-btn"
          onMouseEnter={props.onCounterMouseEnter}
          onMouseLeave={props.onCounterMouseLeave}
          onMouseDown={() => {
            props.onCounterMouseDown();
            props.onIncrement();
          }}
          onMouseUp={props.onCounterMouseUp}
        >
          <canvas ref={props.counterCanvasRef} className="esc-option-canvas" />
          <span
            className="esc-option-label"
            style={{
              transform: props.counterPressed ? "translate(2px, 2px)" : "none",
            }}
          >
            +1
          </span>
        </button>
      </div>
    </section>
  );
}
```
and add this at:
**`src/App.tsx`**
```tsx

// other app code...

import CounterSection from "./components/sections/CounterSection";

// other app code...

const [counterHovered, setCounterHovered] = useState(false);
const [counterPressed, setCounterPressed] = useState(false);
const [counterCount, setCounterCount] = useState(0);

// other app code...

const handleIncrement = () => {
    setCounterCount(prev => prev + 1);
  };

// other app code...

 // Effect: count canvas
  useEffect(() => {
    const canvas = counterCanvasRef.current;
    const bgUrlVal = counterPressed ? escBgDownUrl : escBgUrl;
    const borderUrlVal = counterPressed
      ? escBorderDownUrl
      : escBorderUrl;
    const hoverActive = counterHovered && !counterPressed;
    const hoverUrlVal = escHoverUrl;
    if (!canvas || !bgUrlVal || !borderUrlVal) return;
    let cancelled = false;

    void Promise.all([
      loadDataUrlImage(bgUrlVal),
      loadDataUrlImage(borderUrlVal),
      hoverUrlVal ? loadDataUrlImage(hoverUrlVal) : Promise.resolve(null),
    ])
      .then(([bgImg, borderImg, hoverImg]) => {
        if (cancelled) return;
        drawGlueNineSliceToCanvas(
          canvas,
          bgImg,
          borderImg,
          hoverImg,
          hoverActive,
        );
      })
      .catch((err) => console.error(err));

    return () => {
      cancelled = true;
    };
  }, [
    counterPressed,
    counterHovered,
    escBgUrl,
    escBgDownUrl,
    escBorderUrl,
    escBorderDownUrl,
    escHoverUrl,
  ]);

// other app code...

  <div className="showcase-flow-item showcase-flow-item--counter">
    <CounterSection 
      count={counterCount}                     // ← new
      onIncrement={handleIncrement}
      counterPressed={counterPressed}
      counterCanvasRef={counterCanvasRef}
      onCounterMouseEnter={() => setCounterHovered(true)}
      onCounterMouseLeave={() => {
        setCounterHovered(false);
        setCounterPressed(false);
      }}
      onCounterMouseDown={() => {
        setCounterPressed(true);
      }}
      onCounterMouseUp={() => setCounterPressed(false)}
    />
  </div>
```

> The `esc-option-preview` and `esc-option-label` classes are the WC3-styled button from HeroSection. They give you the gold frame button look for free.

