## Example 5: Timer with setInterval

A section with a running timer — the pattern for the build order timer.

**`src/state/timer.ts`**
```ts
import { createExternalStore } from './createStore';

const runningStore = createExternalStore<boolean>(false);
const elapsedStore = createExternalStore<number>(0); // seconds

let intervalId: ReturnType<typeof setInterval> | null = null;

export function startTimer() {
  if (runningStore.get()) return; // already running
  runningStore.set(true);
  intervalId = setInterval(() => {
    elapsedStore.set(prev => prev + 1);
  }, 1000);
}

export function pauseTimer() {
  if (intervalId !== null) {
    clearInterval(intervalId);
    intervalId = null;
  }
  runningStore.set(false);
}

export function resetTimer() {
  pauseTimer();
  elapsedStore.set(0);
}

export const useTimerRunning = runningStore.useValue;
export const useElapsedSeconds = elapsedStore.useValue;
export const getElapsedSeconds = elapsedStore.get;
```

**`src/components/sections/TimerSection.tsx`**
```tsx
import {
  useTimerRunning,
  useElapsedSeconds,
  startTimer,
  pauseTimer,
  resetTimer,
} from '../../state/timer';

function formatTime(seconds: number): string {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toString().padStart(2, '0')}`;
}

export default function TimerSection() {
  const running = useTimerRunning();
  const elapsed = useElapsedSeconds();

  return (
    <section className="section-card timer-section">
      <h3>Timer</h3>
      <div className="timer-display">{formatTime(elapsed)}</div>
      <div className="timer-controls">
        {running ? (
          <button type="button" className="esc-option-preview" onClick={pauseTimer}>
            <span className="esc-option-label">Pause</span>
          </button>
        ) : (
          <button type="button" className="esc-option-preview" onClick={startTimer}>
            <span className="esc-option-label">Start</span>
          </button>
        )}
        <button type="button" className="esc-option-preview" onClick={resetTimer}>
          <span className="esc-option-label">Reset</span>
        </button>
      </div>
    </section>
  );
}
```

**CSS in `src/global.css`:**
