 81→function rotateCellClockwise(
 82→  atlas: HTMLImageElement,
 83→  cellIndex: number,
 84→  cellW: number,
 85→  cellH: number,
 86→): HTMLCanvasElement {
 87→  const canvas = document.createElement("canvas");
 88→  canvas.width = cellH;
 89→  canvas.height = cellW;
 90→  const ctx = canvas.getContext("2d");
 91→  if (!ctx) return canvas;
 92→  ctx.translate(cellH, 0);
 93→  ctx.rotate(Math.PI / 2);
 94→  ctx.drawImage(atlas, cellIndex * cellW, 0, cellW, cellH, 0, 0, cellW, cellH);
 95→  return canvas;
 96→}
