100→export interface NineSliceTemplateOptions {
101→  cornerPx: number;
102→  insetPx: number;
103→  tileBackground?: boolean;
104→  tileHorizontalEdges?: boolean;
105→  opaqueBaseFill?: string | null;
106→  fillCornerMaxPx?: number;
107→}
108→
109→function drawHorizontallyTiledEdge(
110→  ctx: CanvasRenderingContext2D,
111→  tile: HTMLCanvasElement,
112→  x: number,
113→  y: number,
114→  width: number,
115→  height: number,
116→) {
117→  if (width <= 0 || height <= 0) return;
118→  let drawn = 0;
119→  while (drawn < width) {
120→    const segmentW = Math.min(height, width - drawn);
121→    const srcW = (segmentW / height) * tile.width;
122→    ctx.drawImage(tile, 0, 0, srcW, tile.height, x + drawn, y, segmentW, height);
123→    drawn += segmentW;
124→  }
125→}
126→
127→export function drawTemplateNineSliceToCanvas(
128→  canvas: HTMLCanvasElement,
129→  bgImg: HTMLImageElement,
130→  borderImg: HTMLImageElement,
131→  options: NineSliceTemplateOptions,
132→) {
133→  const cssW = Math.max(1, canvas.clientWidth || 1);
134→  const cssH = Math.max(1, canvas.clientHeight || 1);
135→  const dpr = window.devicePixelRatio || 1;
136→  const pxW = Math.max(1, Math.round(cssW * dpr));
137→  const pxH = Math.max(1, Math.round(cssH * dpr));
138→  if (canvas.width !== pxW || canvas.height !== pxH) {
139→    canvas.width = pxW;
140→    canvas.height = pxH;
141→  }
142→
143→  const ctx = canvas.getContext("2d");
144→  if (!ctx) return;
145→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
146→  ctx.clearRect(0, 0, cssW, cssH);
147→
148→  const atlasW = borderImg.width;
149→  const atlasH = borderImg.height;
150→  const cellW = atlasW / 8;
151→  const sourceCornerMax = Math.max(1, Math.floor(Math.min(cellW, atlasH)));
152→  const corner = Math.max(
153→    1,
154→    Math.floor(Math.min(options.cornerPx, sourceCornerMax, cssW / 2, cssH / 2)),
155→  );
156→  const inset = Math.max(
157→    0,
158→    Math.floor(Math.min(options.insetPx, cssW / 2, cssH / 2)),
159→  );
160→  const innerX = inset;
161→  const innerY = inset;
162→  const innerW = Math.max(0, cssW - inset * 2);
163→  const innerH = Math.max(0, cssH - inset * 2);
164→  const fillCornerCapPx = options.fillCornerMaxPx ?? 8;
165→  const fillCorner = Math.max(
166→    0,
167→    Math.floor(Math.min(corner, fillCornerCapPx, innerW / 2, innerH / 2)),
168→  );
169→
170→  if (innerW > 0 && innerH > 0) {
171→    ctx.save();
172→    ctx.beginPath();
173→    if (fillCorner > 0) {
174→      ctx.roundRect(innerX, innerY, innerW, innerH, fillCorner);
175→    } else {
176→      ctx.rect(innerX, innerY, innerW, innerH);
177→    }
178→    ctx.clip();
179→
180→    if (options.opaqueBaseFill) {
181→      ctx.fillStyle = options.opaqueBaseFill;
182→      ctx.fillRect(innerX, innerY, innerW, innerH);
183→    }
184→    if (options.tileBackground === false) {
185→      ctx.drawImage(bgImg, 0, 0, bgImg.width, bgImg.height, innerX, innerY, innerW, innerH);
186→    } else {
187→      const pattern = ctx.createPattern(bgImg, "repeat");
188→      if (pattern) {
189→        ctx.fillStyle = pattern;
190→        ctx.fillRect(innerX, innerY, innerW, innerH);
191→      }
192→    }
193→    ctx.restore();
194→  }
195→
196→  const drawCell = (idx: number, x: number, y: number, w: number, h: number) => {
197→    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
198→  };
199→
200→  drawCell(4, 0, 0, corner, corner);
201→  drawCell(5, cssW - corner, 0, corner, corner);
202→  drawCell(6, 0, cssH - corner, corner, corner);
203→  drawCell(7, cssW - corner, cssH - corner, corner, corner);
204→
205→  const edgeH = cssH - corner * 2;
206→  if (edgeH > 0) {
207→    drawCell(0, 0, corner, corner, edgeH);
208→    drawCell(1, cssW - corner, corner, corner, edgeH);
209→  }
210→
211→  const edgeW = cssW - corner * 2;
212→  if (edgeW > 0) {
213→    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
214→    const bottomRot = rotateCellClockwise(borderImg, 3, cellW, atlasH);
215→    if (options.tileHorizontalEdges) {
216→      drawHorizontallyTiledEdge(ctx, topRot, corner, 0, edgeW, corner);
217→      drawHorizontallyTiledEdge(ctx, bottomRot, corner, cssH - corner, edgeW, corner);
218→    } else {
219→      ctx.drawImage(topRot, corner, 0, edgeW, corner);
220→      ctx.drawImage(bottomRot, corner, cssH - corner, edgeW, corner);
221→    }
222→  }
223→}
