225→/* ── Glue nine-slice (buttons) ── */
226→
227→export function drawGlueNineSliceToCanvas(
228→  canvas: HTMLCanvasElement,
229→  bgImg: HTMLImageElement,
230→  borderImg: HTMLImageElement,
231→  hoverImg: HTMLImageElement | null,
232→  hovered: boolean,
233→) {
234→  const cssW = Math.max(1, canvas.clientWidth || 1);
235→  const cssH = Math.max(1, canvas.clientHeight || 1);
236→  const dpr = window.devicePixelRatio || 1;
237→  const pxW = Math.max(1, Math.round(cssW * dpr));
238→  const pxH = Math.max(1, Math.round(cssH * dpr));
239→  if (canvas.width !== pxW || canvas.height !== pxH) {
240→    canvas.width = pxW;
241→    canvas.height = pxH;
242→  }
243→
244→  const ctx = canvas.getContext("2d");
245→  if (!ctx) return;
246→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
247→  ctx.clearRect(0, 0, cssW, cssH);
248→
249→  const atlasW = borderImg.width;
250→  const atlasH = borderImg.height;
251→  const cellW = atlasW / 8;
252→  const corner = Math.max(
253→    1,
254→    Math.floor(Math.min(cellW, cssH * 0.35, cssW / 2, cssH / 2)),
255→  );
256→  const inset = Math.max(1, Math.round(corner * 0.25));
257→
258→  ctx.fillStyle = "#000";
259→  ctx.fillRect(inset, inset, cssW - inset * 2, cssH - inset * 2);
260→
261→  const pattern = ctx.createPattern(bgImg, "repeat");
262→  if (pattern) {
263→    ctx.fillStyle = pattern;
264→    ctx.fillRect(inset, inset, cssW - inset * 2, cssH - inset * 2);
265→  }
266→
267→  const drawCell = (
268→    idx: number,
269→    x: number,
270→    y: number,
271→    w: number,
272→    h: number,
273→  ) => {
274→    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
275→  };
276→
277→  drawCell(4, 0, 0, corner, corner);
278→  drawCell(5, cssW - corner, 0, corner, corner);
279→  drawCell(6, 0, cssH - corner, corner, corner);
280→  drawCell(7, cssW - corner, cssH - corner, corner, corner);
281→
282→  const edgeH = cssH - corner * 2;
283→  if (edgeH > 0) {
284→    drawCell(0, 0, corner, corner, edgeH);
285→    drawCell(1, cssW - corner, corner, corner, edgeH);
286→  }
287→
288→  const edgeW = cssW - corner * 2;
289→  if (edgeW > 0) {
290→    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
291→    const bottomRot = rotateCellClockwise(borderImg, 3, cellW, atlasH);
292→    ctx.drawImage(topRot, corner, 0, edgeW, corner);
293→    ctx.drawImage(bottomRot, corner, cssH - corner, edgeW, corner);
294→  }
295→
296→  if (hovered && hoverImg) {
297→    const temp = document.createElement("canvas");
298→    temp.width = pxW;
299→    temp.height = pxH;
300→    const tCtx = temp.getContext("2d");
301→    if (tCtx) {
302→      tCtx.setTransform(dpr, 0, 0, dpr, 0, 0);
303→      tCtx.drawImage(canvas, 0, 0, cssW, cssH);
304→      tCtx.globalCompositeOperation = "source-in";
305→      tCtx.drawImage(hoverImg, 0, 0, cssW, cssH);
306→      ctx.save();
307→      ctx.globalCompositeOperation = "lighter";
308→      ctx.drawImage(temp, 0, 0, cssW, cssH);
309→      ctx.restore();
310→    }
311→  }
312→}
