 6→  type: 'health' | 'mana' | 'xp' | 'build';
 7→  fillPercent: number;
 8→  maxValue?: number;
 9→  height?: number;
10→  hasBorder?: boolean;
11→  renderer: Renderer;
12→}
13→
14→export default function StatBar(props: Props) {
15→  const ref = useRef<HTMLDivElement>(null);
16→
17→  useEffect(() => {
18→    props.renderer.statBars.push({
19→      ref: () => ref.current!,
20→      fillPercent: () => props.fillPercent,
21→      type: props.type,
22→      hasBorder: !!props.hasBorder,
23→    });
24→  }, []);
25→
26→  const barText = () => {
27→    const pct = props.fillPercent;
28→    if (props.type === 'build') return pct + '%';
29→    if (props.maxValue) {
30→      return Math.floor(props.maxValue * pct / 100) + '\u00a0/ ' + props.maxValue;
31→    }
32→    return pct + '%';
33→  };
34→
35→  return (
36→    <div className="bar-row">
37→      <span className="bar-label">{props.label}</span>
38→      <div ref={ref} className="stat-bar" style={{ height: (props.height || 18) + 'px' }}>
39→        <div
40→          className={`bar-fill-img ${props.type}-fill animated-bar`}
41→          style={{ width: props.fillPercent + '%' }}
42→        />
43→        {props.hasBorder && <img className="bar-border-overlay" src="" alt="" />}
44→        <div className="bar-text" style={props.height && props.height < 18 ? { fontSize: '0.6rem' } : {}}>
45→          {barText()}
46→        </div>
47→      </div>
48→    </div>
49→  );
50→}
