        setCheckboxDisabledBgUrl(cbDisabledBg);
        setRadioBgUrl(rbBg);
        setRadioDisabledBgUrl(rbDisabledBg);
        setRadioDotUrl(rbDot);
        setRadioDisabledDotUrl(rbDisabledDot);
      },
    )
    .catch((err) => console.error(err));

  return () => {
    cancelled = true;
  };
}, [race]);

