320→  const cellH = atlas.height;
321→  const cell = Math.max(1, Math.floor(Math.min(cellW, cellH)));
322→  const canvas = document.createElement("canvas");
323→  canvas.width = cell * 3;
324→  canvas.height = cell * 3;
325→  const ctx = canvas.getContext("2d");
326→  if (!ctx) return "";
327→  ctx.clearRect(0, 0, canvas.width, canvas.height);
328→  ctx.imageSmoothingEnabled = false;
329→
330→  const drawCell = (idx: number, x: number, y: number) => {
331→    ctx.drawImage(atlas, idx * cellW, 0, cellW, cellH, x, y, cell, cell);
332→  };
333→
334→  drawCell(4, 0, 0);
335→  drawCell(5, cell * 2, 0);
336→  drawCell(6, 0, cell * 2);
337→  drawCell(7, cell * 2, cell * 2);
338→  drawCell(0, 0, cell);
339→  drawCell(1, cell * 2, cell);
340→
