359→/**
360→ * Hook that drives a canvas element with nine-slice rendering and hover/press
361→ * state. Returns event handlers to spread onto the button element.
362→ */
363→export function useNineSliceButton(urls: NineSliceUrls, disabled?: boolean) {
364→  const canvasRef = useRef<HTMLCanvasElement>(null);
365→  const [hovered, setHovered] = useState(false);
366→  const [pressed, setPressed] = useState(false);
367→
368→  useEffect(() => {
369→    const canvas = canvasRef.current;
370→    const activeBg = disabled ? urls.bgDisabled : pressed ? urls.bgDown : urls.bg;
371→    const activeBorder = disabled
372→      ? urls.borderDisabled
373→      : pressed
374→        ? urls.borderDown
375→        : urls.border;
376→    const hoverActive = hovered && !pressed && !disabled;
377→    if (!canvas || !activeBg || !activeBorder) return;
378→    let cancelled = false;
379→
380→    void Promise.all([
381→      loadDataUrlImage(activeBg),
382→      loadDataUrlImage(activeBorder),
383→      urls.hover && !disabled
384→        ? loadDataUrlImage(urls.hover)
385→        : Promise.resolve(null),
386→    ])
387→      .then(([bgImg, borderImg, hoverImg]) => {
388→        if (cancelled) return;
389→        drawGlueNineSliceToCanvas(canvas, bgImg, borderImg, hoverImg, hoverActive);
390→      })
391→      .catch((err) => console.error(err));
392→
393→    return () => {
394→      cancelled = true;
395→    };
396→  }, [
397→    disabled,
398→    pressed,
399→    hovered,
400→    urls.bg,
401→    urls.bgDown,
402→    urls.bgDisabled,
403→    urls.border,
404→    urls.borderDown,
405→    urls.borderDisabled,
406→    urls.hover,
407→  ]);
408→
409→  const handlers = disabled
410→    ? {}
411→    : {
412→        onMouseEnter: () => setHovered(true),
413→        onMouseLeave: () => {
414→          setHovered(false);
415→          setPressed(false);
416→        },
417→        onMouseDown: () => setPressed(true),
418→        onMouseUp: () => setPressed(false),
419→      };
420→
421→  return { canvasRef, pressed, handlers };
422→}
